// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { useAuth } from "../../contexts/AuthContext";
import { getOverview, getUsers, getRiders, getApprovedCaptains, getPendingCaptains } from "../../services/adminApi";
import { Button, Container, Typography, Table, TableHead, TableRow, TableCell, TableBody } from "@mui/material";

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [overview, setOverview] = useState({});
  const [data, setData] = useState([]);
  const [activeTab, setActiveTab] = useState("overview");

  useEffect(() => {
    fetchOverview();
  }, []);

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    let res;
    if (type === "users") res = await getUsers();
    if (type === "riders") res = await getRiders();
    if (type === "captains") res = await getApprovedCaptains();
    if (type === "pending") res = await getPendingCaptains();
    setData(res?.data[type === "users" ? "users" : type === "riders" ? "riders" : type === "captains" ? "captains" : "pendingCaptains"] || []);
  };

  return (
    <Container>
      <Button variant="contained" color="error" onClick={logout} style={{ marginBottom: 20 }}>
        Logout
      </Button>

      <Typography variant="h4" gutterBottom>Admin Dashboard</Typography>

      <div style={{ marginBottom: 20 }}>
        <Button onClick={() => fetchData("users")} variant="outlined" style={{ marginRight: 5 }}>
          Users ({overview.users || 0})
        </Button>
        <Button onClick={() => fetchData("riders")} variant="outlined" style={{ marginRight: 5 }}>
          Riders ({overview.riders || 0})
        </Button>
        <Button onClick={() => fetchData("captains")} variant="outlined" style={{ marginRight: 5 }}>
          Approved Captains ({overview.captains || 0})
        </Button>
        <Button onClick={() => fetchData("pending")} variant="outlined" style={{ marginRight: 5 }}>
          Pending Captains ({overview.pendingCaptains || 0})
        </Button>
        <Button onClick={() => fetchData("rides")} variant="outlined">
          Rides ({overview.rides || 0})
        </Button>
      </div>

      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Email</TableCell>
            <TableCell>Mobile</TableCell>
            <TableCell>Role</TableCell>
            <TableCell>Approval Status</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {data.length === 0 ? (
            <TableRow>
              <TableCell colSpan={5} align="center">No data found</TableCell>
            </TableRow>
          ) : (
            data.map((item) => (
              <TableRow key={item._id}>
                <TableCell>{item.fullName}</TableCell>
                <TableCell>{item.email}</TableCell>
                <TableCell>{item.mobile}</TableCell>
                <TableCell>{item.role}</TableCell>
                <TableCell>{item.approvalStatus || "-"}</TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>
    </Container>
  );
}
